head.script:
scwin.MSG_CM_CRM_001 = "저장하시겠습니까?" 
scwin.MSG_CM_ERR_001 = "검색조건값을 입력하세요."
scwin.MSG_CM_ERR_002 = "변경된 사항이 없습니다."
scwin.MSG_CM_ERR_003 = "조회된 데이터가 없습니다." 
scwin.MSG_CM_ERR_004 = "사용자별 권한이 존재합니다. 삭제 후 복사하세요." 
scwin.MSG_CM_ERR_005 = "사용자를 먼저 조회하세요."
scwin.MSG_CM_ERR_006 = "프로그램 조회후 사용하세요."

scwin.retrieveYn = "N";

scwin.memJson = $c.data.getMemInfo();
scwin.userId = scwin.memJson.userId;
scwin.userClsCd = (typeof($c.data.getParameter("pUserClsCd")) == "undefined")? "" : $c.data.getParameter("pUserClsCd");
scwin.privGrpId = (typeof($c.data.getParameter("pPrivGrpId")) == "undefined")? "" : $c.data.getParameter("pPrivGrpId");
// scwin.userClsCd = "05";
// scwin.privGrpId = "CO01";

console.log("##### userClsCd : " + scwin.userClsCd);
console.log("##### privGrpId : " + scwin.privGrpId);

//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------   
scwin.onpageload = function() {
    const codeOptions = [ 
        { grpCd : "ZZ010", compID : "lc_userClsCd_param" },
    ];
    $c.data.setCommonCode(codeOptions);
};

// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
scwin.ondataload = function() {
    scwin.init();
    if( $p.getAllParameter().paramData.menuInfo.menuId.indexOf("n") > -1){
        rd_debis.setSelectedIndex(1);
        rd_debis.setDisabled(true);
    } 
};

scwin.init = function() {
    let vparam1 = "";
    if(rd_debis.getValue() == "N") {
        vparam1 = "Ncall";
    }

    const codeOptions1 = [
        { method: "getLuxeComboData"
        , param1: vparam1+"PrivilegeEBC"
        , param2: "retrievePrivilegeGroupDTOList"
        , param3: [""]
        , compID: "lc_privGroup_cond,lc_privGroup" 
        },
        { method: "getLuxeComboData"
        , param1: vparam1+"ProgramEBC"
        , param2: "retrieveSysCdList"
        , param3: [""]
        , compID: "lc_sysCd" 
        },
    ];
    $c.data.setGauceUtil(codeOptions1);

	if ( scwin.userClsCd != "" ){
		lc_userClsCd_param.setValue(scwin.userClsCd);
		$c.gus.cfDisableBtn([lc_userClsCd_param]);
	}else{
		lc_userClsCd_param.setSelectedIndex(0);
	}
    lc_userSearch.setSelectedIndex(0);
    ed_searchUser.setValue("");

    lc_privGroup_cond.setSelectedIndex(0);
    lc_sysCd.setSelectedIndex(0);
    lc_programSearch.setSelectedIndex(0);
    ed_searchProgram.setValue("");

    lc_pgmIdFilter.setSelectedIndex(0);
    ed_pgmNmFilter.setValue("");

    ds_315List.setJSON([]);
    ds_tplPrivilege.setJSON([]);
    ds_412List.setJSON([]);
    ds_411List.setJSON([]);

    gr_315List_spanTotal.setLabel(0);
    gr_412List_spanTotal.setLabel(0);
    gr_411List_spanTotal.setLabel(0);

	if ( scwin.privGrpId != "" ){
		lc_privGroup.setValue(scwin.privGrpId);
		$c.gus.cfDisableBtn([lc_privGroup]);
	}

    cbx_privReserveYn.setValue("0");
    lc_privGroup.setSelectedIndex(0);
    ed_reqId.setValue("");
    ed_reqNm.setValue("");

   	ed_searchUser.focus();
    $c.gus.cfDisableBtn([btn_DeleteAll]);
};    

/**
 * UDC 셋팅이 이후..
 */
scwin.onUdcCompleted = function() {
};
scwin.btn_UserRetrieve_onclick = function (e) {
    scwin.f_Retrieve(0);
};

scwin.btn_ProgramRetrieve_onclick = function (e) {
    scwin.f_Retrieve(1);
};

//-------------------------------------------------------------------------
// function name : f_DeleteAll
// function desc : 삭제
//-------------------------------------------------------------------------
scwin.f_DeleteAll = function() {     
    // for(var i=ds_412List.getRowCount(); i>=1;i--){
    //     ds_412List.DeleteRow(i);
    // }
    // $c.data.deleteRows(gr_412List);
    for (var i=0;i<ds_412List.getRowCount();i++) {
        var rowJson = ds_412List.getRowJSON(i);
        if( rowJson.rowStatus == "C" ) {
            ds_412List.removeRow(i);
        } else {
            ds_412List.deleteRow(i);
        }
    }
};

//-------------------------------------------------------------------------
// function name : f_DsSearch
// function desc : 필터
//-------------------------------------------------------------------------
scwin.f_Filter = function() {
    ds_412List.UseFilter=true;
    ds_412List.Filter();
    /**************
    * 2006.4.16 이진욱 수정
    * 내용: 조회시 사용자가 여러명일경우 각각에 대해서 필터링이 되는 경우를 막기위해서
    *      필터링 이후 자동 필터 안되도록 필터링 옵션을 false로 바꾼다.
    **************/
    ds_412List.UseFilter=false;
};

