//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function(idx) {

    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }

    if(idx == "1"){
        if(lc_privGroup_cond.getValue() != "00" && lc_sysCd.getValue() != "00"){
            $c.win.alert("권한그룹 또는 시스템구분 중 1개의 조회 조건만 사용할 수 있습니다.");
            lc_privGroup_cond.setValue("00");
            lc_privGroup_cond.focus();
            return false;
        }
        if( lc_sysCd.getValue().trim()=="" ){
            $c.win.alert("시스템구분은 필수선택사항입니다.");
            lc_sysCd.focus();
            return false
        }
        var arrJson = { sysCls:lc_sysCd.getValue()
                      , programLupCond:lc_programSearch.getValue()
                      , qryCntn: ed_searchProgram.getValue()
                      , userId: ds_315List.getCellData( ds_315List.getRowPosition(), "userId" )
                      , deptPrivYn: ""
                      , useYn: "1"
                      , grpCls: lc_privGroup_cond.getValue()
                      };

        sbm_411List.action = "/"+debis+"cm.bc.comnmgnt.programmgnt.RetrieveUserEachPrivilegeExceptProgramListCMD.do";
        $c.sbm.execute(sbm_411List, arrJson);
    }else{

        // 사용자 조회 
        vSearchCond = lc_userSearch.getValue();
        vSearchContent = ed_searchUser.getValue();
        var vUserClsCd = lc_userClsCd_param.getValue();
        if(vSearchCond == "0"){
            // ds_retrieve.nameValue(1, "userNm") = vSearchContent;
            ds_retrieve.set("userNm", vSearchContent);
            ds_retrieve.set("userId", "");
        }else{
            ds_retrieve.set("userNm", "");
            ds_retrieve.set("userId", vSearchContent);
        }

        ds_retrieve.set("userClsCd", vUserClsCd);
        // ds_retrieve.UseChangeInfo = false; // 매번 조회 하도록 한다.
        scwin.retrieveYn= "N";
        sbm_315List.action = "/"+debis+"cm.bc.comnmgnt.usermgnt.cmd.RetrieveUserListCMD.do";
        $c.sbm.execute(sbm_315List);
    }
};

//-------------------------------------------------------------------------
// function name : f_MainRetrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.f_MainRetrieve = function(userId) {
    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }

    var arrJson = {
        "arrJSON": 
        { userId: userId},
        "OUT_DS1":{},
        "OUT_DS2":{}
    };
    sbm_userEachScreenPriv.action = "/"+debis+"cm.bc.comnmgnt.privmgnt.RetrieveUserEachScreenPrivilegeListCMD.do";
    $c.sbm.execute( sbm_userEachScreenPriv, arrJson );
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {

    let debis = "";
    if(rd_debis.getValue() == "N") {
        debis = "ncall.";
    }
    sbm_save.action = "/"+debis+"cm.bc.comnmgnt.privmgnt.SaveUserEachScreenPrivilegeCMD.do";

    var ds_412ListModi = ds_412List.getModifiedJSON();
    var ds_tplPrivilegeModi = ds_tplPrivilege.getModifiedJSON();

	//변경한 데이터가 있는지 체크한다. 
    if( (ds_412ListModi.length == 0) && (ds_tplPrivilegeModi.length == 0) ) {
        $c.win.alert(scwin.MSG_CM_ERR_002);
        return;
    }

    let confirmResult = await $c.win.confirm(scwin.MSG_CM_CRM_001);
    if (confirmResult) {
        $c.sbm.execute(sbm_save);
    }

};

//-------------------------------------------------------------------------
// function name : f_LMove
// function desc : 좌이동
//-------------------------------------------------------------------------
scwin.f_LMove = function() {

    var pgmCnt  = ds_411List.getRowCount();
    var privCnt = ds_412List.getRowCount();
    var userCnt = ds_315List.getRowCount();
    var userId = ds_315List.getCellData(ds_315List.getRowPosition(), "userId");

    if(userCnt<1){
        $c.win.alert("프로그램을 추가할 사용자를 조회해주십시오.");
        ed_searchUser.focus();
        return false;
    }

    if(pgmCnt<1){
        $c.win.alert(scwin.MSG_CM_ERR_006);
        return;
    }else{
        // gr_412List.ColumnProp("qryYn","HeadCheck") = true;

		for(var i=0; i<pgmCnt; i++){
			var chkYn = ds_411List.getCellData(i, "chk");
			var pgmId = ds_411List.getCellData(i, "pgmId");
			var pgmNm = ds_411List.getCellData(i, "pgmNm");
            var deptPrivYn = ds_411List.getCellData(i, "deptPrivYn");

            var ds_411RowStatus = ds_411List.getRowStatus(i);

            // console.log("=====chkYn=="+chkYn);
			if(chkYn == "1"){

                // 0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
                // "dlt_dataList1.getRowStatus(0);
                // rowIndex에 해당하는 행의 상태 코드(문자) 반환 (초기상태:R, 갱신:U, 삽입:C, 삭제:D, 삽입 후 삭제:V)
                // dlt_dataList1.getRowStatusValue(0);
                // rowIndex에 해당하는 행의 상태 코드를 숫자로 반환 (초기상태:0, 갱신:1, 삽입:2, 삭제:3, 삽입 후 삭제:4)"

                if(ds_411RowStatus=="C"){

                    for(var j=0; j<privCnt; j++){
                        var privPgmId = ds_412List.getCellData(j, "pgmId");
                        if(pgmId == privPgmId){
                            // ds_412List.NameValue(k, "chk") = "F";
                            // ds_412List.Undo(k);
                            ds_412List.undoRow(j);
                            break;
                        }else{
                            continue;
                        }
                    }

                }else if(ds_411RowStatus=="U"){

					// 로우상태가 Normal인 경우
					var addFlag = "A";
					for(var j=0; j<privCnt; j++){
                        var privPgmId = ds_412List.getCellData(j, "pgmId");
						if(pgmId == privPgmId){
							addFlag = "N";
							break;
						}else{
							continue;
						}
					}

                    if(addFlag == "A"){

                        // var rowIndex = ds_412List.getTotalRow();
                        // ds_412List.insertRow(rowIndex);
                        let rowIndex = ds_412List.insertRow();

                        ds_412List.setCellData(rowIndex, "userId", userId);
                        ds_412List.setCellData(rowIndex, "pgmId", pgmId); 
                        ds_412List.setCellData(rowIndex, "pgmNm", pgmNm); 
                        ds_412List.setCellData(rowIndex, "insYn", 0); 
                        ds_412List.setCellData(rowIndex, "qryYn", 1); 					
                        ds_412List.setCellData(rowIndex, "modYn", 0); 
                        ds_412List.setCellData(rowIndex, "delYn", 0); 
                        //ds_412List.setCellData(rowIndex, "prtnYn", 0);
                        ds_412List.setCellData(rowIndex, "prtnYn", 1);					
                        //ds_412List.setCellData(rowIndex, "xlsDwnldYn", 0);
                        ds_412List.setCellData(rowIndex, "xlsDwnldYn", 1);
                        ds_412List.setCellData(rowIndex, "deptPrivYn", deptPrivYn);
                        ds_412List.setCellData(rowIndex, "chk", "0");

                        gr_412List.setFocusedCell(rowIndex, 0);
                    }
                }
			}
		}

        for(var i=(pgmCnt-1); i>=0; i--){
			var chkYn = ds_411List.getCellData(i, "chk");
			if(chkYn == "1"){
				ds_411List.removeRow(i);
			}
		}
    }

    if(ds_412List.getTotalRow() > 0){
        $c.gus.cfEnableBtnOnly([btn_Save, btn_DeleteAll, btn_Filter]);
    }
};

//-------------------------------------------------------------------------
// function name : f_RMove
// function desc : 우이동
//-------------------------------------------------------------------------
scwin.f_RMove = function() {
    //cfProgressWinOpen();
    var pgmCnt  = ds_411List.getRowCount();
	var privCnt = ds_412List.getRowCount();

    if(privCnt<1){
        $c.win.alert(scwin.MSG_CM_ERR_005);
        return;
    }else{

		for(var i=0; i<privCnt; i++){
			var chkYn = ds_412List.getCellData(i, "chk");
			var pgmId = ds_412List.getCellData(i, "pgmId");
			var pgmNm = ds_412List.getCellData(i, "pgmNm");
			var deptPrivYn = ds_412List.getCellData(i, "deptPrivYn");

			if(chkYn == "1"){
				var addFlag = "A";
				for(var j=0; j<=pgmCnt; j++){
					var privPgmId = ds_411List.getCellData(j, "pgmId");
					if(pgmId == privPgmId){
						addFlag = "N";
						break;
					}else{
						continue;
					}
				}

				if(addFlag == "A"){
                    var rowIndex = ds_411List.getTotalRow();
                    ds_411List.insertRow(rowIndex);

					ds_411List.setCellData(rowIndex, "pgmId", pgmId); 
					ds_411List.setCellData(rowIndex, "pgmNm", pgmNm);
					ds_411List.setCellData(rowIndex, "chk", 0);
                    ds_411List.setCellData(rowIndex, "side", "R");
                    ds_411List.setCellData(rowIndex, "deptPrivYn", deptPrivYn);

					ds_411List.modifyAllStatus("R");

                    gr_411List.setFocusedCell(rowIndex, 0);
				}
				// ds_412List.removeRow(i);
			}
		} 
        // 0: Normal, 1: Insert, 2: Delete, 3: Update, 4: Logical
		for(var i=(privCnt-1); i>=0; i--){
			var chkYn = ds_412List.getCellData(i, "chk");
            var rowStatus = ds_412List.getRowStatus(i);
			if(chkYn == "1"){
                if( rowStatus == "C"){
                    ds_412List.removeRow(i);
                } else {
                    ds_412List.deleteRow(i);
                } 
			}
		}        
    }

    if(ds_412List.getRowCount() > 0){
        // cfEnableBtnOnly([b_Save,b_UndoAll,b_DeleteAll,b_Filter]);
        // $c.gus.cfEnableBtnOnly([btn_Save,btn_UndoAll,btn_DeleteAll,btn_Filter]);
        $c.gus.cfEnableBtnOnly([btn_Save, btn_DeleteAll, btn_Filter]);
    }
};

//-------------------------------------------------------------------------
// function name : f_copyPrivlege()
// function desc : 그룹복사
//-------------------------------------------------------------------------
//scwin.f_copyPrivlege('privlege')
//scwin.f_copyPrivlege('user')
scwin.f_copyPrivlege = async function(pType) {
    var vUserId = "";   // 카피사용자
    var vCopyTrgtUserId = "";   // 카피 대상사용자
    var vPrivGrpId = ""; // 권한그룹ID

    dma_privilegeCopy.setEmptyValue();
    vCopyTrgtUserId = ds_315List.getCellData( ds_315List.getRowPosition(), "userId" );

    if(vCopyTrgtUserId.trim()==""){
        $c.win.alert("권한을 복사할  대상을 선택해주십시오.");
        return false;
    }

    var vPrivReserveYn = cbx_privReserveYn.getValue();  // 기존권한유지여부
    var vPrivReserveStatus = "0";
    var vConfirmText = "권한복사를 할 경우 이전 권한은 삭제됩니다. 권한복사를 계속 진행하시겠습니까?";

    if(vPrivReserveYn == "1"){
        vConfirmText = "기존 사용자권한은 유지되고 추가되는 권한만 복사됩니다. 계속 진행하시겠습니까?";
        vPrivReserveStatus = "1";
    }

    // var vConfirm = confirm(vConfirmText);
    let confirmResult = await $c.win.confirm(vConfirmText);
    if (confirmResult) {
        if(pType=="user"){
            // 개인권한복사

            //vUserId = lux_privUser.ValueOfIndex("code",lux_privUser.index);
            vUserId = ed_reqId.getValue();
            if(vUserId.trim()==""){
                $c.win.alert("권한복사 사용자를 정확하게 선택해 주십시오.");
                ed_reqId.focus();
                return false;
            }
            dma_privilegeCopy.set("userId", vUserId);            
            // dma_privilegeCopy.set("privGrpId", "");
            dma_privilegeCopy.set("copyTrgtUserId", vCopyTrgtUserId);
            dma_privilegeCopy.set("privReserveYn", vPrivReserveStatus);
            dma_privilegeCopy.set("pType", "user");

        }else{
            // 권한그룹복사

            vPrivGrpId = lc_privGroup.getValue();

            if(vPrivGrpId.trim()==""){
                $c.win.alert("권한복사 사용자를 정확하게 선택해 주십시오.");
                lc_privGroup.focus();
                return false;
            }
            // dma_privilegeCopy.set("userId", "");
            dma_privilegeCopy.set("privGrpId", vPrivGrpId);
            dma_privilegeCopy.set("copyTrgtUserId", vCopyTrgtUserId);
            dma_privilegeCopy.set("privReserveYn", vPrivReserveStatus);
            dma_privilegeCopy.set("pType", "group");

        }

        let debis = "";
        if(rd_debis.getValue() == "N") {
            debis = "ncall.";
        }
        sbm_privilegeCopy.action = "/"+debis+"cm.bc.comnmgnt.privmgnt.CreatePrivilegeCopyCMD.do";
        $c.sbm.execute(sbm_privilegeCopy);
    }
};

