scwin.sbm_315List_submitdone = async function (e) {
    var rowCnt = ds_315List.getRowCount();
    gr_315List_spanTotal.setLabel(rowCnt);

    if (rowCnt == 0) {
        await $c.win.alert(scwin.MSG_CM_ERR_003);
        ds_412List.removeAll();
    }else{
        scwin.retrieveYn = "Y";
        gr_315List.setFocusedCell(0, 0);
        scwin.f_MainRetrieve(ds_315List.getCellData(0, "userId"));	
    }
};

scwin.sbm_userEachScreenPriv_submitdone = async function (e) {
    var rowCnt = ds_412List.getRowCount();
    gr_412List_spanTotal.setLabel(rowCnt);

    if( rowCnt == 0 ){
        // await $c.win.alert(scwin.MSG_CM_ERR_003);
        $c.gus.cfEnableKeyData();
    }else if( rowCnt > 0 ){
        gr_412List.setFocusedCell(0, 0);
        $c.gus.cfEnableBtnOnly([btn_Save, btn_DeleteAll, btn_Filter]);
        // disable 처리
        $c.gus.cfDisableKeyData();

        scwin.f_Filter();
    }

    var rowCntt = ds_tplPrivilege.getRowCount();
    if( rowCntt > 0 ){
        gr_tplPrivilege.setFocusedCell(0, 0);
    }

};

