scwin.f_Filter = function () {

	var pgmCond = lc_pgmIdFilter.getValue();
	var pgmName = ed_pgmNmFilter.getValue();
    var rcolumnId = "pgmNm";

	switch (pgmCond) {
		case "1":
            rcolumnId = "pgmNm";
			break;
		case "2":
            rcolumnId = "pgmId";
			break;
	}    

    ds_412List.removeColumnFilterAll();
    if( pgmCond > 0 ) {
        $c.data.dataListFilter(ds_412List, "LIKE", true, 
            {colId : rcolumnId, func : function(cellData, tmpParam, rowIdx) {
                if(cellData.indexOf(pgmName) > -1){
                    return true;
                }
                return false;   // return이 true인 경우 적용하고 false인 경우 넘김
            } 
            });
    } else {
        // ds_451List.removeColumnFilterAll();
    }

};

